import { useState, useEffect, useMemo } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { Card, Container, Row, Col, Spinner, Alert, Button, Form } from "react-bootstrap";
import api from "../services/api";

function EventDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [event, setEvent] = useState(null);
  const [ticketTypes, setTicketTypes] = useState([]);
  const [quantities, setQuantities] = useState({});
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchEvent = async () => {
      try {
        setLoading(true);
        const response = await api.get(`/users/events/${id}`);
        
        if (response.data?.success && response.data?.data) {
          const eventData = response.data.data;
          const ticketList = eventData.ticketTypes || [];
          setEvent(eventData);
          setTicketTypes(ticketList);

          const initialQuantities = {};
          ticketList.forEach((ticket) => {
            initialQuantities[ticket.id] = 0;
          });
          setQuantities(initialQuantities);
        } else {
          setError("Không tìm thấy sự kiện này");
        }
      } catch (err) {
        console.error("Lỗi khi lấy sự kiện:", err);
        setError("Có lỗi xảy ra khi tải sự kiện");
      } finally {
        setLoading(false);
      }
    };

    fetchEvent();
  }, [id]);

  // Hàm xử lý thay đổi số lượng vé
  const handleQuantityChange = (ticket, value) => {
    let quantity = Number(value);
    if (Number.isNaN(quantity) || quantity < 0) quantity = 0;

    const maxAllowed = Math.min(Number(ticket.available || 0), Number(ticket.max_per_order || 0));
    if (quantity > maxAllowed) quantity = maxAllowed;

    setQuantities((prev) => ({
      ...prev,
      [ticket.id]: quantity,
    }));
  };

  // Tính tổng số vé đã chọn
  const totalTickets = useMemo(() => {
    return ticketTypes.reduce((sum, ticket) => {
      return sum + Number(quantities[ticket.id] || 0);
    }, 0);
  }, [ticketTypes, quantities]);

  // Tính tổng số tiền
  const totalAmount = useMemo(() => {
    return ticketTypes.reduce((sum, ticket) => {
      const qty = Number(quantities[ticket.id] || 0);
      return sum + qty * Number(ticket.price || 0);
    }, 0);
  }, [ticketTypes, quantities]);

  // Tính giá trị canBuy để kiểm tra xem người dùng có thể mua vé không
  const canBuy = useMemo(() => {
    return ticketTypes.some(
      (ticket) =>
        Number(ticket.available || 0) > 0 &&
        Number(ticket.max_per_order || 0) > 0 &&
        ticket.status === "active"
    );
  }, [ticketTypes]);

  // Hàm xử lý khi người dùng nhấn "Mua vé"
  const handleCreateOrder = async () => {
    try {
      setError("");

      const items = ticketTypes
        .filter((ticket) => Number(quantities[ticket.id] || 0) > 0)
        .map((ticket) => ({
          ticket_type_id: ticket.id,
          quantity: Number(quantities[ticket.id]),
        }));

      if (items.length === 0) {
        setError("Vui lòng chọn ít nhất 1 vé");
        return;
      }

      const response = await api.post("/users/orders/create", { items });
      if (response.data?.success) {
        const orderId = response.data.data?.orderId;
        setTimeout(() => {
          navigate(`/payment/${orderId}`);
        }, 700);
      } else {
        setError(response.data?.message || "Đặt vé thất bại");
      }
    } catch (err) {
      console.error("Lỗi khi tạo đơn hàng:", err);
      setError("Đã xảy ra lỗi khi đặt vé");
    }
  };

  if (loading) {
    return (
      <div className="d-flex justify-content-center align-items-center" style={{ height: "100vh" }}>
        <Spinner animation="border" variant="primary" />
      </div>
    );
  }

  if (error) {
    return (
      <Container className="text-center mt-5">
        <Alert variant="danger">{error}</Alert>
      </Container>
    );
  }

  if (!event) {
    return (
      <Container className="text-center mt-5">
        <Alert variant="warning">Không tìm thấy sự kiện này.</Alert>
      </Container>
    );
  }

  return (
    <Container className="my-5">
      <Row>
        <Col md={8}>
          <Card>
            <Card.Img
              variant="top"
              src={event.banner_image ? `/images/${event.banner_image}` : "/images/default-banner.jpg"}
              alt={event.title}
            />
            <Card.Body>
              <Card.Title>{event.title}</Card.Title>
              <Card.Text>{event.description}</Card.Text>
              <Card.Text><strong>Địa điểm:</strong> {event.location}</Card.Text>
              <Card.Text><strong>Ngày sự kiện:</strong> {new Date(event.event_date).toLocaleDateString("vi-VN")}</Card.Text>
            </Card.Body>
          </Card>
        </Col>
        <Col md={4}>
          <Card>
            <Card.Body>
              <Card.Title>Thông tin sự kiện</Card.Title>
              <Card.Text><strong>Người tổ chức:</strong> {event.organizer_name}</Card.Text>
              <Card.Text><strong>Trạng thái:</strong> {event.status}</Card.Text>
            </Card.Body>
          </Card>
        </Col>
      </Row>

      <Row>
        <Col md={12}>
          <div className="tb-ticket-section">
            <div className="tb-ticket-section-title">Chọn vé</div>

            {ticketTypes.length === 0 ? (
              <div className="tb-ticket-empty">Hiện chưa có loại vé nào cho sự kiện này.</div>
            ) : (
              <div className="tb-ticket-list">
                {ticketTypes.map((ticket) => {
                  const maxAllowed = Math.min(Number(ticket.available || 0), Number(ticket.max_per_order || 0));

                  return (
                    <div className="tb-ticket-card" key={ticket.id}>
                      <div className="tb-ticket-card-head">
                        <div className="tb-ticket-name-wrap">
                          <div className="tb-ticket-name">{ticket.name}</div>
                          <div className="tb-ticket-desc">
                            {ticket.description || "Không có mô tả"}
                          </div>
                        </div>

                        <div className="tb-ticket-price">
                          {Number(ticket.price || 0).toLocaleString("vi-VN")} đ
                        </div>
                      </div>

                      <div className="tb-ticket-body">
                        <ul className="tb-ticket-features">
                          <li>Còn lại: {ticket.available ?? 0} vé</li>
                          <li>Tối đa mỗi đơn: {ticket.max_per_order ?? 0} vé</li>
                          <li>
                            Chuyển nhượng:{" "}
                            {Number(ticket.transferable) === 1 ? "Có" : "Không"}
                          </li>
                        </ul>

                        <div className="tb-ticket-qty-box">
                          <Form.Label className="mb-2 text-white fw-semibold">Chọn số lượng</Form.Label>
                          <Form.Control
                            type="number"
                            min={0}
                            max={maxAllowed}
                            value={quantities[ticket.id] || 0}
                            onChange={(e) => handleQuantityChange(ticket, e.target.value)}
                            disabled={maxAllowed <= 0}
                          />
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        </Col>
      </Row>

      <Row>
        <Col md={12}>
          <div className="tb-order-summary">
            <div className="tb-order-title">Tóm tắt đơn hàng</div>
            <div className="tb-order-row">
              <span>Tổng số vé</span>
              <strong>{totalTickets}</strong>
            </div>
            <div className="tb-order-row">
              <span>Tổng tiền</span>
              <strong>{totalAmount.toLocaleString("vi-VN")} đ</strong>
            </div>
            <Button
              className="tb-buy-main-btn"
              onClick={handleCreateOrder}
              disabled={!canBuy || totalTickets === 0 || submitting}
            >
              {submitting ? "Đang tạo đơn..." : "Mua vé ngay"}
            </Button>
          </div>
        </Col>
      </Row>
    </Container>
  );
}

export default EventDetailPage;
